import java.io.File;
import java.util.Scanner;

public class SecurePathTraversal {
    private static final String BASE_DIRECTORY = "/path/to/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a file name: ");
        String fileName = scanner.nextLine();

        if (isValidFileName(fileName)) {
            File file = new File(BASE_DIRECTORY + fileName);

            if (file.exists()) {
                System.out.println("File found at: " + file.getAbsolutePath());
            } else {
                System.out.println("File not found.");
            }
        } else {
            System.out.println("Invalid file name.");
        }
    }

    private static boolean isValidFileName(String fileName) {
        // Implement your validation logic here
        // Example: Allow only alphanumeric characters and limit length
        return fileName.matches("[a-zA-Z0-9]+\\.txt") && fileName.length() <= 50;
    }
}

